function getLevelCfg(lv){
  const wi=Math.floor((lv-1)/3)%WORLDS.length;
  const li=(lv-1)%3;
  const w=WORLDS[wi];
  return{world:w,wi,li,count:Math.min(2+Math.floor((lv+1)/2),8),spd:.45+wi*.12+li*.06,platforms:(PLATSETS[w.bg]||PLATSETS.istanbul)[li]};
}

