function showMenu(){
  document.getElementById('goTitle').style.display='none';
  document.getElementById('goScore').style.display='none';
  document.getElementById('ov').style.display='flex';
  document.getElementById('mctrl').style.display='none';
  resumeAC(); refreshActivePlayerLabel(); if(typeof startMenuMusic==='function')startMenuMusic(); ensureProdMenuButtons(); if(!lRaf)animLogo();
}
function hideMenu(){
  document.getElementById('ov').style.display='none';
  if(lRaf){cancelAnimationFrame(lRaf);lRaf=null}
}
function showGameOver(){
  running=false;(typeof stopAllMusic==='function'?stopAllMusic():stopBGM());{const st=normStats();st.games++;saveStats(st);checkAchievements();}addHi(score,level);
  const best=getHi()[0],isNew=best&&best.s===score&&getHi().filter(x=>x.s===score).length===1;
  let goF=0;
  function goAnim(){
    ctx.save();
    ctx.globalAlpha=Math.min(goF/35,.92);ctx.fillStyle='#030310';ctx.fillRect(0,0,GW,GH);ctx.globalAlpha=1;
    const cy=GH/2,a=Math.min(goF/35,1);
    ctx.save();ctx.globalAlpha=a;
    // panel
    const pg=ctx.createLinearGradient(GW/2-160,cy-100,GW/2+160,cy+120);
    pg.addColorStop(0,'#0d0d28');pg.addColorStop(1,'#1a1a40');
    ctx.fillStyle=pg;ctx.beginPath();ctx.roundRect(GW/2-165,cy-110,330,240,12);ctx.fill();
    ctx.strokeStyle='#ff475744';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(GW/2-165,cy-110,330,240,12);ctx.stroke();
    // title
    ctx.font='bold 34px Courier New';ctx.textAlign='center';
    ctx.fillStyle='#ff4757';ctx.shadowColor='#ff4757';ctx.shadowBlur=24;
    ctx.fillText('OYUN BİTTİ',GW/2,cy-58);ctx.shadowBlur=0;
    // score
    ctx.font='bold 24px Courier New';ctx.fillStyle='#ffd700';ctx.shadowColor='#ffd700';ctx.shadowBlur=12;
    ctx.fillText(score.toLocaleString(),GW/2,cy-8);ctx.shadowBlur=0;
    ctx.font='12px Courier New';ctx.fillStyle='#aaa';ctx.fillText('SKOR',GW/2,cy+14);
    // level
    ctx.font='14px Courier New';ctx.fillStyle='#888';ctx.fillText('BÖLÜM: '+level,GW/2,cy+44);
    if(isNew){
      ctx.font='bold 16px Courier New';ctx.fillStyle='#ffd700';ctx.shadowColor='#ffd700';ctx.shadowBlur=14;
      ctx.fillText('🏆 YENİ REKOR!',GW/2,cy+74);ctx.shadowBlur=0;
    }
    if(goF>45){
      ctx.globalAlpha=(goF-45)/20*a;ctx.font='11px Courier New';ctx.fillStyle='#444';
      ctx.fillText('Menüden devam edebilirsin',GW/2,cy+108);ctx.globalAlpha=1;
    }
    ctx.restore();ctx.restore();
    goF++;
    if(goF<80)requestAnimationFrame(goAnim);
    else{
      document.getElementById('goTitle').style.display='block';
      document.getElementById('goTitle').textContent='OYUN BİTTİ';
      document.getElementById('goScore').style.display='block';
      document.getElementById('goScore').innerHTML=`Skor: <b style="color:#ffd700">${score.toLocaleString()}</b> — Bölüm: ${level}`+(isNew?' 🏆<span style="color:#ffd700"> YENİ REKOR!</span>':'');
      document.getElementById('ov').style.display='flex';
      document.getElementById('mctrl').style.display='none';
      if(typeof startMenuMusic==='function')startMenuMusic();
      ensureGameOverButtons();
      if(!lRaf)animLogo();
    }
  }
  goAnim();
}
document.getElementById('btnStart').onclick=startGame;

// ═══════════════════════════════════════════════════
// DELTA-TIME — 60fps normalize
// requestAnimationFrame, 90/120Hz ekranlarda çok daha sık çağrılır.
// dt: her frame'de geçen süreyi 60fps'e göre normalize eder (60fps = 1.0).
// Tüm fizik ve sayaç işlemleri bu dt ile çarpılarak ekran yenileme
// hızından bağımsız hale gelir.
// ═══════════════════════════════════════════════════
let _lastFrameTime = 0;
let dt = 1; // normalized delta (60fps = 1.0)
const DT_MIN = 0.5, DT_MAX = 2.0; // sınırlar: donma/patlamayı önler

// ═══════════════════════════════════════════════════
// GAME LOOP
// ═══════════════════════════════════════════════════
function loop(now){
  if(!running)return;

  // ── Delta-time hesabı ────────────────────────────
  if(_lastFrameTime===0)_lastFrameTime=now;
  const rawDt=(now-_lastFrameTime)/1000; // saniye cinsinden
  _lastFrameTime=now;
  // 60fps = 1.0; 120fps = 0.5 frame/step → normalize et
  dt=Math.min(DT_MAX, Math.max(DT_MIN, rawDt*60));

  ctx.globalAlpha=1;ctx.setLineDash([]);ctx.clearRect(0,0,GW,GH);
  drawBG();drawPlatforms();
  if(dbl>0)dbl-=dt;if(slowT>0)slowT-=dt;if(magT>0)magT-=dt;if(!isFinite(ghost)||ghost<0)ghost=0;if(ghost>0)ghost-=dt;if(giantT>0)giantT-=dt;
  if(quickfire>0)quickfire-=dt;if(barrierT>0)barrierT-=dt;if(clockT>0)clockT-=dt;
  if(fireCooldown>0)fireCooldown-=dt;
  if(comboTimer>0){comboTimer-=dt;if(comboTimer<=0)combo=0;}
  updatePowerBar();drawHUDCanvas();

  // ── BARRIER ─────────────────────────────────────
  if(barrierT>0){
    const by=CEIL+(FLOOR-CEIL)/2;
    const ba=barrierT/180;
    ctx.save();
    ctx.globalAlpha=ba*.8;
    ctx.strokeStyle='#0984e3';ctx.lineWidth=4;
    ctx.shadowColor='#0984e3';ctx.shadowBlur=14;
    ctx.setLineDash([12,6]);
    ctx.beginPath();ctx.moveTo(0,by);ctx.lineTo(GW,by);ctx.stroke();
    ctx.setLineDash([]);ctx.shadowBlur=0;ctx.globalAlpha=1;
    ctx.restore();
    // pop balloons that touch barrier
    for(let j=balloons.length-1;j>=0;j--){
      const b=balloons[j];
      if(Math.abs(b.y-by)<b.r+4){
        for(let k=0;k<12;k++)parts.push(new Part(b.x,b.y,b.col.f));
        const pts=([0,100,200,500][b.sz]||0)*(dbl>0?2:1);
        score+=pts;document.getElementById('elScore').textContent=t('score')+': '+score;
        const kids=b.split();balloons.splice(j,1);balloons.push(...kids);
        SFX.pop(b.sz); recordBalloonPop(b);
        if(Math.random()<.4)bonuses.push(new Bonus(b.x,b.y,rndBonus()));
      }
    }
  }

  // ── FIRE COOLDOWN HUD (top-left arc) ─────────────
  {
    const cd=quickfire>0?FIRE_CD_QUICK:FIRE_CD_BASE;
    const fill=1-Math.min(fireCooldown/cd,1);
    const cx=28,cy=CEIL+18,cr=12;
    ctx.save();
    // bg circle
    ctx.strokeStyle='rgba(255,255,255,.15)';ctx.lineWidth=3;
    ctx.beginPath();sarc(cx,cy,cr);ctx.stroke();
    // fill arc
    ctx.strokeStyle=fill>=1?'#2ed573':quickfire>0?'#fdcb6e':'#ff4757';
    ctx.lineWidth=3;
    ctx.shadowColor=fill>=1?'#2ed573':'#ff4757';ctx.shadowBlur=fill>=1?8:0;
    ctx.beginPath();
    ctx.arc(cx,cy,cr,-Math.PI/2,-Math.PI/2+TAU*fill);
    ctx.stroke();ctx.shadowBlur=0;
    // icon
    ctx.fillStyle='rgba(255,255,255,.8)';ctx.font='8px serif';
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText(fill>=1?'🎯':'⏳',cx,cy);
    ctx.restore();
  }

  // PROJECTILES
  for(let i=projs.length-1;i>=0;i--){
    const p=projs[i];p.update(dt);p.draw();
    if(!p.active){projs.splice(i,1);continue}
    if(p instanceof Hook){
      // Hook handles its own balloon collision internally in _hit()
      continue;
    } else {
      const hbs=p.hb();
      for(let j=balloons.length-1;j>=0;j--){
        const b=balloons[j];
        const onR=circ(b.x,b.y,b.r,hbs.rope.x,hbs.rope.y,hbs.rope.w,hbs.rope.h);
        const onT=circ(b.x,b.y,b.r,hbs.tip.x,hbs.tip.y,hbs.tip.w,hbs.tip.h);
        const onM=hbs.mid?circ(b.x,b.y,b.r,hbs.mid.x,hbs.mid.y,hbs.mid.w,hbs.mid.h):false;
        if(onR||onT||onM){
          for(let k=0;k<16;k++)parts.push(new Part(b.x,b.y,b.col.f));
          const pts=([0,100,200,500][b.sz]||0)*(dbl>0?2:1);
          ftexts.push(new FText(b.x,b.y-b.r-8,'+'+pts,'#ffd700'));
          const kids=b.split();balloons.splice(j,1);balloons.push(...kids);
          score+=pts;document.getElementById('elScore').textContent=t('score')+': '+score;
          SFX.pop(b.sz); recordBalloonPop(b);
          if(Math.random()<.45)bonuses.push(new Bonus(b.x,b.y,rndBonus()));
          // impact at hit point (tip or mid)
          if(p instanceof Proj){
            p.impactX=onT?(hbs.tip.x+11):(onM?(hbs.mid.x+11):p.baseX);
            p.impactY=onT?(hbs.tip.y+13):(onM?(hbs.mid.y+13):b.y);
            p._triggerImpact();
          } else {
            p.active=false;
          }
          break;
        }
      }
    }
  }

  // BALLOONS
  for(const b of balloons){
    b.update(dt);b.draw();
    if(hitCD<=0&&player.inv<=0&&ghost<=0){
      if(circ(b.x,b.y,b.r,player.x-10,player.y+6,20,34)){
        if(shield){
          shield=false;player.inv=55;hitCD=22;
          ftexts.push(new FText(player.x,player.y,'🛡 KALKAN!','#a29bfe'));
          SFX.bonus();
        } else {
          lives--;levelHitTaken=true;updLives();player.inv=100;hitCD=55;SFX.hit();haptic(70);
          if(lives<=0){SFX.die();setTimeout(()=>showGameOver(),300);running=false;return}
        }
      }
    }
  }
  if(hitCD>0)hitCD-=dt;

  // BONUSES
  for(let i=bonuses.length-1;i>=0;i--){bonuses[i].update(dt);bonuses[i].draw();if(!bonuses[i].active)bonuses.splice(i,1)}

  // PARTICLES
  for(let i=parts.length-1;i>=0;i--){parts[i].update(dt);parts[i].draw();if(parts[i].life<=0)parts.splice(i,1)}
  ctx.globalAlpha=1;ctx.setLineDash([]);

  // FLOATING TEXTS
  for(let i=ftexts.length-1;i>=0;i--){ftexts[i].update(dt);ftexts[i].draw();if(ftexts[i].life<=0)ftexts.splice(i,1)}
  ctx.globalAlpha=1;ctx.textAlign='left';ctx.shadowBlur=0;

  player.update(dt);player.draw();

  // Tutorial fade
  if(tutTimer>0){tutTimer-=dt;document.getElementById('tut').style.opacity=tutTimer<40?(tutTimer/40).toString():'1'}
  else document.getElementById('tut').style.opacity='0';

  // Anti-stuck: if all balloons are gone, any remaining hook/chain should retract and not block the stage.
  if(balloons.length===0){
    projs.forEach(p=>{
      if(p instanceof Hook && (p.phase==='active'||p.phase==='extending'||p.phase==='rising')){
        p.phase='dying';
        p.dyingFrame=Math.max(p.dyingFrame||0,8);
      }
    });
  }

  // Level clear
  if(balloons.length===0&&bonuses.length===0&&projs.every(p=>!(p instanceof Hook&&p.active&&(p.phase==='active'||p.phase==='extending'||p.phase==='rising')))){
    running=false;
    {const st=normStats(); if(!levelHitTaken)st.noHitLevels++; if(level===5){const ms=Date.now()-runStartTs;if(!st.bestSpeedMs||ms<st.bestSpeedMs)st.bestSpeedMs=ms;} saveStats(st);checkAchievements();}
    const prevCfg=getLevelCfg(level),nextLv=level+1,nextCfg=getLevelCfg(nextLv);
    level++;
    if(nextCfg.wi!==prevCfg.wi){
      SFX.levelup();
      const pn=typeof prevCfg.world.name==='object'?prevCfg.world.name[lang]:prevCfg.world.name;
      const nn=typeof nextCfg.world.name==='object'?nextCfg.world.name[lang]:nextCfg.world.name;
      showMap(prevCfg.world,nextCfg.world,`${nextCfg.world.vh} ${pn} → ${nn}`,()=>{
        setBGMWorld(nextCfg.wi);
        showTransition(nextCfg.world,()=>{spawnLevel(level);startBGM(nextCfg.wi);running=true;_lastFrameTime=0;rafGame=requestAnimationFrame(loop)});
      });
    } else {
      SFX.levelup();spawnLevel(level);const c=getLevelCfg(level);startBGM(c.wi);running=true;_lastFrameTime=0;rafGame=requestAnimationFrame(loop);
    }
    return;
  }
  rafGame=requestAnimationFrame(loop);
}

// ═══════════════════════════════════════════════════
// FIRE
// ═══════════════════════════════════════════════════
function fireNormal(){
  if(!running||!player)return;
  resumeAC();
  if(fireCooldown>0)return;
  const ap=projs.filter(p=>p instanceof Proj&&p.active);
  const max=dualShot?2:1;
  if(ap.length>=max)return;
  fireCooldown=quickfire>0?FIRE_CD_QUICK:FIRE_CD_BASE;
  lastShot=Date.now();
  if(player)player.fireT=14;

  // Mızrak: adamın baktığı yönde, boyunun yarısı kadar önüne çarpar
  // Adamın boyu ~88px (scale 0.62 * ~142), yarısı ~44px → dünya coord ~50px ileri
  const halfBody = 50;
  const spearStartX = player.x + player.face * halfBody; // baktığı yönde ileri
  const spearStartY = player.y + 44; // ayak hizasından başlar (görünmez)

  const dwnProj = new Proj(spearStartX, spearStartY, giantT>0, true);
  dwnProj._invisible = true; // çizilmeyecek
  projs.push(dwnProj);
  SFX.fire();
  if(dualShot&&ap.length===0){
    setTimeout(()=>{if(running&&player){
      const dwnProj2 = new Proj(player.x + player.face*halfBody + 20, player.y+44, giantT>0, true);
      dwnProj2._invisible = true;
      projs.push(dwnProj2);
    }},75);
  }
}
function fireHook(){
  if(!running||!player)return;
  projs.push(new Hook(player.x,player.y+8));
}

// ═══════════════════════════════════════════════════
// START
// ═══════════════════════════════════════════════════
function startGame(){
  const inp=document.getElementById('nameFirstInput');
  const warn=document.getElementById('nameWarn');
  const raw=inp?String(inp.value||'').trim():'';
  if(raw){playerName=cleanPlayerName(raw);try{localStorage.setItem('pangPlayerName',playerName)}catch{}}
  // localStorage'dan yüklenmiş isim 'PLAYER' ise uyar; tamamen boşsa da uyar
  if(!playerName||playerName==='PLAYER'){
    if(warn){warn.textContent=lang==='tr'?'Lütfen adını yaz!':'Please enter your name!';}
    if(inp)inp.focus();
    return;
  }
  if(warn)warn.textContent='';
  showCharSelect();
}

// ═══════════════════════════════════════════════════
// INPUT
// ═══════════════════════════════════════════════════
addEventListener('keydown',e=>{
  keys[e.key]=true;
  if(e.key===' '){e.preventDefault();fireNormal()}
  if(e.key==='ArrowUp'||e.key==='w'){
    e.preventDefault();
    // Her zaman zıpla — merdivende de, platformda da
    if(player)player.requestJump();
  }
  if(e.key==='ArrowDown'||e.key==='s')e.preventDefault();
});
addEventListener('keyup',e=>{keys[e.key]=false});

function holdBtn(id,k){
  const el=document.getElementById(id);if(!el)return;
  el.addEventListener('touchstart',e=>{e.preventDefault();keys[k]=true},{passive:false});
  el.addEventListener('touchend',  e=>{e.preventDefault();keys[k]=false},{passive:false});
  el.addEventListener('mousedown', ()=>keys[k]=true);
  el.addEventListener('mouseup',   ()=>keys[k]=false);
  el.addEventListener('mouseleave',()=>keys[k]=false);
}

// ── VIRTUAL JOYSTICK ─────────────────────────────
const joyCvs=document.getElementById('joyCanvas');
const joyCtx=joyCvs.getContext('2d');
const JOY_SIZE=160;
const JOY_BASE_R=58, JOY_THUMB_R=28;
const JOY_CX=80, JOY_CY=80; // center in canvas
let joyActive=false, joyThumbX=JOY_CX, joyThumbY=JOY_CY, joyTouchId=null;

function drawJoystick(){
  joyCtx.clearRect(0,0,JOY_SIZE,JOY_SIZE);
  // outer glow ring
  joyCtx.strokeStyle='rgba(255,255,255,.10)';joyCtx.lineWidth=3;
  joyCtx.beginPath();joyCtx.arc(JOY_CX,JOY_CY,JOY_BASE_R+6,0,TAU);joyCtx.stroke();
  // base fill
  const bg=joyCtx.createRadialGradient(JOY_CX,JOY_CY,4,JOY_CX,JOY_CY,JOY_BASE_R);
  bg.addColorStop(0,'rgba(255,255,255,.12)');bg.addColorStop(1,'rgba(255,255,255,.04)');
  joyCtx.fillStyle=bg;
  joyCtx.beginPath();joyCtx.arc(JOY_CX,JOY_CY,JOY_BASE_R,0,TAU);joyCtx.fill();
  // base ring
  joyCtx.strokeStyle='rgba(255,255,255,.30)';joyCtx.lineWidth=2;
  joyCtx.beginPath();joyCtx.arc(JOY_CX,JOY_CY,JOY_BASE_R,0,TAU);joyCtx.stroke();
  // direction arrows (subtle)
  joyCtx.fillStyle='rgba(255,255,255,.14)';joyCtx.font='bold 11px sans-serif';joyCtx.textAlign='center';joyCtx.textBaseline='middle';
  joyCtx.fillText('◀',JOY_CX-JOY_BASE_R+12,JOY_CY);
  joyCtx.fillText('▶',JOY_CX+JOY_BASE_R-12,JOY_CY);
  joyCtx.fillText('▲',JOY_CX,JOY_CY-JOY_BASE_R+12);
  joyCtx.fillText('▼',JOY_CX,JOY_CY+JOY_BASE_R-12);
  // thumb shadow
  joyCtx.fillStyle='rgba(0,0,0,.25)';
  joyCtx.beginPath();joyCtx.arc(joyThumbX+3,joyThumbY+3,JOY_THUMB_R,0,TAU);joyCtx.fill();
  // thumb
  const tg=joyCtx.createRadialGradient(joyThumbX-5,joyThumbY-5,2,joyThumbX,joyThumbY,JOY_THUMB_R);
  tg.addColorStop(0,'rgba(255,255,255,.80)');
  tg.addColorStop(.5,'rgba(255,255,255,.40)');
  tg.addColorStop(1,'rgba(200,200,200,.18)');
  joyCtx.fillStyle=tg;
  joyCtx.beginPath();joyCtx.arc(joyThumbX,joyThumbY,JOY_THUMB_R,0,TAU);joyCtx.fill();
  joyCtx.strokeStyle='rgba(255,255,255,.55)';joyCtx.lineWidth=2;
  joyCtx.beginPath();joyCtx.arc(joyThumbX,joyThumbY,JOY_THUMB_R,0,TAU);joyCtx.stroke();
  // thumb inner dot
  joyCtx.fillStyle='rgba(255,255,255,.45)';
  joyCtx.beginPath();joyCtx.arc(joyThumbX,joyThumbY,8,0,TAU);joyCtx.fill();
}
drawJoystick();

function joyMove(tx,ty){
  const dx=tx-JOY_CX, dy=ty-JOY_CY;
  const dist=Math.sqrt(dx*dx+dy*dy);
  const clamp=Math.min(dist,JOY_BASE_R);
  const ang=Math.atan2(dy,dx);
  joyThumbX=JOY_CX+Math.cos(ang)*clamp;
  joyThumbY=JOY_CY+Math.sin(ang)*clamp;
  keys.ArrowLeft=dx<-12;
  keys.ArrowRight=dx>12;
  // joystick yukarı = zıpla
  if(dy<-22 && !keys._joyUpPrev && player){
    player.requestJump();
  }
  keys._joyUpPrev=dy<-22;
  keys.ArrowDown=dy>22;
  drawJoystick();
}
function joyReset(){
  joyThumbX=JOY_CX;joyThumbY=JOY_CY;
  keys.ArrowLeft=false;keys.ArrowRight=false;keys.ArrowDown=false;keys._joyUpPrev=false;
  joyActive=false;joyTouchId=null;
  drawJoystick();
}

joyCvs.addEventListener('touchstart',e=>{
  e.preventDefault();
  const touch=e.changedTouches[0];
  joyTouchId=touch.identifier;joyActive=true;
  const r=joyCvs.getBoundingClientRect();
  const s=r.width/JOY_SIZE;
  joyMove((touch.clientX-r.left)/s,(touch.clientY-r.top)/s);
},{passive:false});
joyCvs.addEventListener('touchmove',e=>{
  e.preventDefault();
  for(const touch of e.changedTouches){
    if(touch.identifier===joyTouchId){
      const r=joyCvs.getBoundingClientRect();const s=r.width/JOY_SIZE;
      joyMove((touch.clientX-r.left)/s,(touch.clientY-r.top)/s);
    }
  }
},{passive:false});
joyCvs.addEventListener('touchend',e=>{
  e.preventDefault();
  for(const touch of e.changedTouches){if(touch.identifier===joyTouchId)joyReset();}
},{passive:false});
joyCvs.addEventListener('touchcancel',()=>joyReset());

// ── JOYSTICK MODU butonları ──
function addJumpBtn(id){
  const el=document.getElementById(id);if(!el)return;
  el.addEventListener('touchstart',e=>{e.preventDefault();if(player)player.requestJump();},{passive:false});
  el.addEventListener('mousedown',()=>{if(player)player.requestJump();});
}
function addFireBtn(id){
  const el=document.getElementById(id);if(!el)return;
  el.addEventListener('touchstart',e=>{e.preventDefault();fireNormal();},{passive:false});
  el.addEventListener('mousedown',()=>fireNormal());
}
addJumpBtn('btnUp');
addFireBtn('btnFire');

// ── D-PAD MODU butonları ──
function holdBtn2(id,k){
  const el=document.getElementById(id);if(!el)return;
  el.addEventListener('touchstart',e=>{e.preventDefault();keys[k]=true;},{passive:false});
  el.addEventListener('touchend',  e=>{e.preventDefault();keys[k]=false;},{passive:false});
  el.addEventListener('touchcancel',e=>{e.preventDefault();keys[k]=false;},{passive:false});
  el.addEventListener('mousedown', ()=>keys[k]=true);
  el.addEventListener('mouseup',   ()=>keys[k]=false);
  el.addEventListener('mouseleave',()=>keys[k]=false);
}
holdBtn2('btnLeft','ArrowLeft');
holdBtn2('btnRight','ArrowRight');
addJumpBtn('btnUpD');
addFireBtn('btnFireD');

