// Android/WebView layout safety patch
(function(){
  const _showMenuLayout = typeof showMenu==='function' ? showMenu : null;
  if(_showMenuLayout){
    showMenu=function(){
      _showMenuLayout.apply(this,arguments);
      setTimeout(()=>{try{resize()}catch(e){}},30);
      setTimeout(()=>{try{resize()}catch(e){}},250);
    };
  }
  const _startWithControllerLayout = typeof startWithController==='function' ? startWithController : null;
  if(_startWithControllerLayout){
    startWithController=function(type){
      _startWithControllerLayout.apply(this,arguments);
      setTimeout(()=>{try{resize()}catch(e){}},30);
      setTimeout(()=>{try{resize()}catch(e){}},300);
    };
  }
})();


// ═══════════════════════════════════════════════════
// SAFE ORIENTATION FLOW PATCH v6
// Menü tarafında ASLA bloklama yok: Android input/play donması düzeldi.
// Macera başladıktan sonra: landscape zorunlu. Menüye dönünce landscape kapanır.
// ═══════════════════════════════════════════════════
(function(){
  let gameNeedsLandscape = false;
  let pendingControllerType = null;
  let pausedByOrientation = false;

  function isTouchDevice(){
    return ('ontouchstart' in window) || ((navigator.maxTouchPoints||0) > 0);
  }
  function viewportSize(){
    const vv = window.visualViewport;
    return {
      w: Math.round((vv && vv.width) || window.innerWidth || document.documentElement.clientWidth || 0),
      h: Math.round((vv && vv.height) || window.innerHeight || document.documentElement.clientHeight || 0)
    };
  }
  function isLandscapeNow(){ const v=viewportSize(); return v.w > v.h; }

  function ensureRotateOverlay(){
    let ov = document.getElementById('rotateLandscapeOv');
    if(ov) return ov;
    ov = document.createElement('div');
    ov.id = 'rotateLandscapeOv';
    ov.innerHTML = '<div class="rotatePhoneBox"><div class="rotatePhoneIcon">📱↔️</div><div class="rotatePhoneTitle" id="rotatePhoneTitle">TELEFONU YATAY ÇEVİR</div><div class="rotatePhoneText" id="rotatePhoneText">Macera modu landscape oynanır.</div></div>';
    (document.getElementById('gc') || document.body).appendChild(ov);
    return ov;
  }
  function setOverlayText(mode){
    const title=document.getElementById('rotatePhoneTitle');
    const text=document.getElementById('rotatePhoneText');
    const en=(typeof lang!=='undefined' && lang==='en');
    if(mode==='portrait'){
      if(title) title.textContent = en ? 'ROTATE YOUR PHONE VERTICAL' : 'TELEFONU DİKEY ÇEVİR';
      if(text) text.textContent = en ? 'Menu is used in portrait mode.' : 'Menü dikey modda kullanılır.';
    }else{
      if(title) title.textContent = en ? 'ROTATE YOUR PHONE' : 'TELEFONU YATAY ÇEVİR';
      if(text) text.textContent = en ? 'Adventure mode is played in landscape.' : 'Macera modu landscape oynanır.';
    }
  }
  function showLandscapeOverlay(){
    const ov = ensureRotateOverlay();
    setOverlayText('landscape');
    ov.style.display='flex';
    ov.style.pointerEvents='all';
  }
  function hideRotateOverlay(){
    const ov=document.getElementById('rotateLandscapeOv');
    if(ov){ ov.style.display='none'; ov.style.pointerEvents='none'; }
  }

  async function tryLockLandscape(){
    // Landscape lock çoğu Android WebView'da fullscreen ister. Bu sadece kullanıcı Play'e bastıktan sonra çalışır.
    try{
      const el=document.documentElement;
      const req=el.requestFullscreen||el.webkitRequestFullscreen||el.mozRequestFullScreen||el.msRequestFullscreen;
      if(!document.fullscreenElement && req){ await req.call(el).catch(()=>{}); }
    }catch(e){}
    try{ if(screen.orientation && screen.orientation.lock) await screen.orientation.lock('landscape').catch(()=>{}); }catch(e){}
  }
  function leaveGameOrientation(){
    gameNeedsLandscape=false;
    pendingControllerType=null;
    pausedByOrientation=false;
    hideRotateOverlay();
    document.body.classList.remove('game-landscape-required');
    document.body.classList.add('menu-portrait-required');
    // Menüde portrait lock denemiyoruz. Android/Median'da input ve butonları dondurabiliyor.
    try{ if(screen.orientation && screen.orientation.unlock) screen.orientation.unlock(); }catch(e){}
    try{
      if(document.fullscreenElement && document.exitFullscreen) document.exitFullscreen().catch(()=>{});
    }catch(e){}
    setTimeout(()=>{try{resize()}catch(e){}},80);
    setTimeout(()=>{try{resize()}catch(e){}},300);
  }
  function enterGameOrientation(){
    gameNeedsLandscape=true;
    document.body.classList.add('game-landscape-required');
    document.body.classList.remove('menu-portrait-required');
  }

  function canRunGameLoop(){
    const ov=document.getElementById('ov');
    const settings=document.getElementById('settingsOv');
    const menuHidden=!ov || ov.style.display==='none';
    const settingsHidden=!settings || settings.style.display==='none';
    return gameNeedsLandscape && menuHidden && settingsHidden && typeof player!=='undefined' && !!player;
  }
  function orientationTick(){
    if(!gameNeedsLandscape || !isTouchDevice()){
      hideRotateOverlay();
      return;
    }
    if(!isLandscapeNow()){
      showLandscapeOverlay();
      if(typeof running!=='undefined' && running){
        pausedByOrientation=true;
        running=false;
        try{ if(typeof rafGame!=='undefined' && rafGame){ cancelAnimationFrame(rafGame); rafGame=null; } }catch(e){}
      }
      return;
    }
    hideRotateOverlay();
    if(pendingControllerType){
      const type=pendingControllerType;
      pendingControllerType=null;
      try{ __pangBaseStartWithControllerSafe(type); }catch(e){ console.error(e); }
      forceMobileControlsVisible(type);
      setTimeout(()=>{try{resize()}catch(e){}},60);
      setTimeout(()=>{try{resize()}catch(e){}},300);
      return;
    }
    if(pausedByOrientation && canRunGameLoop()){
      pausedByOrientation=false;
      try{
        running=true;
        if(typeof _lastFrameTime!=='undefined') _lastFrameTime=0;
        if(typeof rafGame!=='undefined' && !rafGame) rafGame=requestAnimationFrame(loop);
      }catch(e){}
    }
  }

  function forceMobileControlsVisible(type){
    if(!isTouchDevice()) return;
    try{
      type = type || selectedController || 'joystick';
      const m=document.getElementById('mctrl');
      if(m){
        m.style.setProperty('display','block','important');
        m.style.setProperty('position','fixed','important');
        m.style.setProperty('inset','0','important');
        m.style.setProperty('width','100vw','important');
        m.style.setProperty('height','100vh','important');
        m.style.setProperty('pointer-events','none','important');
        m.style.setProperty('z-index','999','important');
      }
      const joy=document.getElementById('joyCvsWrap');
      const dpad=document.getElementById('dpadWrap');
      if(joy){
        joy.style.setProperty('display', type==='joystick' ? 'block' : 'none', 'important');
        joy.style.setProperty('position','absolute','important');
        joy.style.setProperty('inset','0','important');
        joy.style.setProperty('pointer-events','none','important');
      }
      if(dpad){
        dpad.style.setProperty('display', type==='dpad' ? 'flex' : 'none', 'important');
        dpad.style.setProperty('position','absolute','important');
        dpad.style.setProperty('inset','0','important');
        dpad.style.setProperty('pointer-events','none','important');
      }
      ['joyCanvas','btnLeft','btnRight','btnUp','btnUpD','btnFire','btnFireD'].forEach(id=>{
        const el=document.getElementById(id);
        if(el){
          el.style.setProperty('pointer-events','all','important');
          el.style.setProperty('touch-action','none','important');
        }
      });
    }catch(e){}
  }

  const __pangBaseStartWithControllerSafe = startWithController;
  window.__pangBaseStartWithControllerSafe = __pangBaseStartWithControllerSafe;
  startWithController = function(type){
    selectedController = type || selectedController || 'joystick';
    enterGameOrientation();
    resumeAC();
    tryLockLandscape();
    if(isTouchDevice() && !isLandscapeNow()){
      pendingControllerType=selectedController;
      try{ hideControllerSelect(); }catch(e){}
      try{ hideMenu(); }catch(e){}
      try{ const m=document.getElementById('mctrl'); if(m)m.style.display='none'; }catch(e){}
      showLandscapeOverlay();
      setTimeout(orientationTick,180);
      setTimeout(orientationTick,700);
      return;
    }
    __pangBaseStartWithControllerSafe(selectedController);
    forceMobileControlsVisible(selectedController);
    setTimeout(orientationTick,80);
    setTimeout(()=>forceMobileControlsVisible(selectedController),180);
    setTimeout(orientationTick,350);
  };

  if(typeof showMenu==='function'){
    const __pangBaseShowMenuSafe=showMenu;
    showMenu=function(){
      leaveGameOrientation();
      return __pangBaseShowMenuSafe.apply(this,arguments);
    };
  }
  if(typeof softReturnToMainMenu==='function'){
    const __pangBaseSoftReturnSafe=softReturnToMainMenu;
    softReturnToMainMenu=function(){
      leaveGameOrientation();
      return __pangBaseSoftReturnSafe.apply(this,arguments);
    };
  }
  if(typeof showGameOver==='function'){
    const __pangBaseGameOverSafe=showGameOver;
    showGameOver=function(){
      // Game over menü overlayine döner; burada landscape zorlamasını kapatıyoruz.
      leaveGameOrientation();
      return __pangBaseGameOverSafe.apply(this,arguments);
    };
  }

  window.addEventListener('resize', orientationTick, {passive:true});
  window.addEventListener('orientationchange', ()=>{setTimeout(orientationTick,120);setTimeout(orientationTick,450);}, {passive:true});
  if(window.visualViewport) window.visualViewport.addEventListener('resize', orientationTick, {passive:true});
  document.addEventListener('fullscreenchange', ()=>setTimeout(orientationTick,150));
  document.addEventListener('webkitfullscreenchange', ()=>setTimeout(orientationTick,150));

  setTimeout(()=>{ document.body.classList.add('menu-portrait-required'); hideRotateOverlay(); },120);
})();


// ═══════════════════════════════════════════════════
// V8 HARD FIX — sadece 2 şey:
// 1) Landscape oyun ekranını viewport'a tam bas
// 2) Seçilen joystick/dpad kontrolünü oyun boyunca zorla görünür tut
// ═══════════════════════════════════════════════════
(function(){
  let __pangSelectedCtrlV8 = window.selectedController || 'joystick';

  function vv(){
    const v=window.visualViewport;
    return {
      w:Math.max(1,Math.round((v&&v.width)||window.innerWidth||document.documentElement.clientWidth||640)),
      h:Math.max(1,Math.round((v&&v.height)||window.innerHeight||document.documentElement.clientHeight||360))
    };
  }
  function landscapeActive(){
    const s=vv();
    const menu=document.getElementById('ov');
    const menuHidden=!menu || menu.style.display==='none';
    return document.body.classList.contains('game-landscape-required') && s.w>s.h && menuHidden;
  }

  function forceFullLandscapeCanvas(){
    const s=vv();
    const gc=document.getElementById('gc');
    const c=document.getElementById('c');
    if(!gc||!c)return;

    if(landscapeActive()){
      document.documentElement.style.setProperty('--app-height',s.h+'px');
      gc.style.setProperty('position','fixed','important');
      gc.style.setProperty('inset','0','important');
      gc.style.setProperty('width',s.w+'px','important');
      gc.style.setProperty('height',s.h+'px','important');
      gc.style.setProperty('display','block','important');
      gc.style.setProperty('overflow','hidden','important');
      gc.style.setProperty('background','#000','important');

      // 640x480 native canvası CSS ile ekrana TAM basıyoruz.
      // Böylece eski 4:3 hesap yüzünden sağ/sol siyah boşluk kalmaz.
      c.style.setProperty('position','absolute','important');
      c.style.setProperty('left','0','important');
      c.style.setProperty('top','0','important');
      c.style.setProperty('width',s.w+'px','important');
      c.style.setProperty('height',s.h+'px','important');
      c.style.setProperty('max-width','none','important');
      c.style.setProperty('max-height','none','important');
      c.style.setProperty('margin','0','important');
      c.style.setProperty('display','block','important');
      c.style.setProperty('object-fit','fill','important');

      ['hud','powerHud','tut'].forEach(id=>{const el=document.getElementById(id); if(el){el.style.setProperty('width',s.w+'px','important');}});
    }
  }

  function forceControls(type){
    if(type) __pangSelectedCtrlV8=type;
    if(!landscapeActive())return;
    const typeNow=__pangSelectedCtrlV8 || window.selectedController || 'joystick';
    const m=document.getElementById('mctrl');
    const joy=document.getElementById('joyCvsWrap');
    const dpad=document.getElementById('dpadWrap');
    const joyCanvas=document.getElementById('joyCanvas');
    if(!m)return;

    m.style.setProperty('display','block','important');
    m.style.setProperty('position','fixed','important');
    m.style.setProperty('left','0','important');
    m.style.setProperty('top','0','important');
    m.style.setProperty('right','0','important');
    m.style.setProperty('bottom','0','important');
    m.style.setProperty('width','100vw','important');
    m.style.setProperty('height','100vh','important');
    m.style.setProperty('height','100dvh','important');
    m.style.setProperty('z-index','2147483000','important');
    m.style.setProperty('pointer-events','none','important');

    if(joy){
      joy.style.setProperty('display',typeNow==='joystick'?'block':'none','important');
      joy.style.setProperty('position','fixed','important');
      joy.style.setProperty('inset','0','important');
      joy.style.setProperty('width','100vw','important');
      joy.style.setProperty('height','100vh','important');
      joy.style.setProperty('height','100dvh','important');
      joy.style.setProperty('pointer-events','none','important');
    }
    if(dpad){
      dpad.style.setProperty('display',typeNow==='dpad'?'block':'none','important');
      dpad.style.setProperty('position','fixed','important');
      dpad.style.setProperty('inset','0','important');
      dpad.style.setProperty('width','100vw','important');
      dpad.style.setProperty('height','100vh','important');
      dpad.style.setProperty('height','100dvh','important');
      dpad.style.setProperty('pointer-events','none','important');
    }
    if(joyCanvas){
      joyCanvas.style.setProperty('display','block','important');
      joyCanvas.style.setProperty('position','fixed','important');
      joyCanvas.style.setProperty('left','18px','important');
      joyCanvas.style.setProperty('bottom','14px','important');
      joyCanvas.style.setProperty('width','150px','important');
      joyCanvas.style.setProperty('height','150px','important');
      joyCanvas.style.setProperty('pointer-events','all','important');
      joyCanvas.style.setProperty('z-index','2147483001','important');
    }

    // joystick modundaki sağ buton kolonunu yakala
    if(joy){
      const rightCol=joy.querySelector('div');
      if(rightCol){
        rightCol.style.setProperty('display','flex','important');
        rightCol.style.setProperty('position','fixed','important');
        rightCol.style.setProperty('right','18px','important');
        rightCol.style.setProperty('bottom','18px','important');
        rightCol.style.setProperty('z-index','2147483001','important');
        rightCol.style.setProperty('pointer-events','all','important');
      }
    }
    // dpad modundaki sol ve sağ kolonlar
    if(dpad){
      const kids=dpad.children;
      if(kids[0]){
        kids[0].style.setProperty('display','flex','important');
        kids[0].style.setProperty('position','fixed','important');
        kids[0].style.setProperty('left','18px','important');
        kids[0].style.setProperty('bottom','18px','important');
        kids[0].style.setProperty('z-index','2147483001','important');
        kids[0].style.setProperty('pointer-events','all','important');
      }
      if(kids[1]){
        kids[1].style.setProperty('display','flex','important');
        kids[1].style.setProperty('position','fixed','important');
        kids[1].style.setProperty('right','18px','important');
        kids[1].style.setProperty('bottom','18px','important');
        kids[1].style.setProperty('z-index','2147483001','important');
        kids[1].style.setProperty('pointer-events','all','important');
      }
    }

    ['btnLeft','btnRight','btnUp','btnUpD','btnFire','btnFireD'].forEach(id=>{
      const el=document.getElementById(id);
      if(el){
        el.style.setProperty('display','flex','important');
        el.style.setProperty('pointer-events','all','important');
        el.style.setProperty('touch-action','none','important');
        el.style.setProperty('z-index','2147483002','important');
      }
    });
  }

  const oldStart = typeof startWithController==='function' ? startWithController : null;
  if(oldStart){
    startWithController=function(type){
      __pangSelectedCtrlV8=type||__pangSelectedCtrlV8||'joystick';
      window.selectedController=__pangSelectedCtrlV8;
      const r=oldStart.apply(this,arguments);
      [50,180,450,900,1500,2500,3500,5000].forEach(ms=>setTimeout(()=>{forceFullLandscapeCanvas();forceControls(__pangSelectedCtrlV8);},ms));
      return r;
    };
  }

  const oldResize = typeof resize==='function' ? resize : null;
  if(oldResize){
    resize=function(){
      const r=oldResize.apply(this,arguments);
      forceFullLandscapeCanvas();
      forceControls(__pangSelectedCtrlV8);
      return r;
    };
  }

  function tick(){
    forceFullLandscapeCanvas();
    forceControls(__pangSelectedCtrlV8);
  }
  window.addEventListener('resize',()=>setTimeout(tick,30),{passive:true});
  window.addEventListener('orientationchange',()=>{setTimeout(tick,80);setTimeout(tick,350);setTimeout(tick,900);},{passive:true});
  if(window.visualViewport) window.visualViewport.addEventListener('resize',()=>setTimeout(tick,30),{passive:true});
  setInterval(tick,350);
})();

// ═══════════════════════════════════════════════════
// V11 MUSIC RESYNC HOOK — ekran/controller fixine dokunmaz
// Sadece mevcut audio.js motoruna durum değişince yeniden sync dedirtir.
// ═══════════════════════════════════════════════════
(function(){
  function audioSyncLater(){
    try{ if(typeof window.__pangAudioSync==='function') window.__pangAudioSync(); }catch(e){}
    setTimeout(()=>{try{ if(typeof window.__pangAudioSync==='function') window.__pangAudioSync(); }catch(e){}},220);
    setTimeout(()=>{try{ if(typeof window.__pangAudioSync==='function') window.__pangAudioSync(); }catch(e){}},900);
  }
  ['pointerdown','touchstart','click','keydown'].forEach(ev=>document.addEventListener(ev,audioSyncLater,{passive:true}));
  window.addEventListener('orientationchange',audioSyncLater,{passive:true});
  window.addEventListener('resize',audioSyncLater,{passive:true});
  if(typeof startWithController==='function'){
    const __v11Start=startWithController;
    startWithController=function(type){
      try{ if(typeof window.resumeAC==='function') window.resumeAC(); }catch(e){}
      const r=__v11Start.apply(this,arguments);
      audioSyncLater();
      return r;
    };
  }
  if(typeof showMenu==='function'){
    const __v11ShowMenu=showMenu;
    showMenu=function(){
      const r=__v11ShowMenu.apply(this,arguments);
      try{ if(typeof window.startMenuMusic==='function') window.startMenuMusic(); }catch(e){}
      audioSyncLater();
      return r;
    };
  }
  if(typeof showMap==='function'){
    const __v11ShowMap=showMap;
    showMap=function(){
      try{ if(typeof window.playMapMusic==='function') window.playMapMusic(); }catch(e){}
      const r=__v11ShowMap.apply(this,arguments);
      audioSyncLater();
      return r;
    };
  }
  if(typeof showTransition==='function'){
    const __v11ShowTrans=showTransition;
    showTransition=function(){
      try{ if(typeof window.playMapMusic==='function') window.playMapMusic(); }catch(e){}
      const r=__v11ShowTrans.apply(this,arguments);
      audioSyncLater();
      return r;
    };
  }
})();
